import{Body,Controller,Headers,Post,RawBodyRequest,Req,UseGuards}from'@nestjs/common';import{ApiBearerAuth,ApiTags}from'@nestjs/swagger';import type{Request}from'express';import{CurrentUser}from'../common/decorators/current-user.decorator';import{JwtGuard}from'../common/guards/jwt.guard';import{PersonaService}from'./persona.service';
@ApiTags('Vendor identity')@Controller('vendors/identity')export class PersonaController{constructor(private readonly persona:PersonaService){}@ApiBearerAuth()@UseGuards(JwtGuard)@Post('inquiry')inquiry(@CurrentUser()user:{sub:string}){return this.persona.create(user.sub)}@Post('webhooks/persona')webhook(@Req()request:RawBodyRequest<Request>,@Headers('persona-signature')signature:string|undefined,@Body()body:Record<string,unknown>){if(!request.rawBody)throw new Error('Raw request body is unavailable');this.persona.verify(request.rawBody,signature);return this.persona.webhook(body)}}
